import math
import itertools

class Solution:
    def getMinSwaps(self, num: str, k: int) -> int:
        num_list = list(num)
        n = len(num_list)
        count = math.factorial(n - 1)
        sorted_num = sorted(num_list)

        for i in range(k - 1):
            for j in range(n - 1, 0, -1):
                if num_list[j] != sorted_num[j]:
                    for idx in range(j - 1, -1, -1):
                        if num_list[idx] < num_list[j] and num_list[idx] != sorted_num[idx]:
                            num_list[idx], num_list[j] = num_list[j], num_list[idx]
                            break
                    break

        swaps = 0
        for i in range(n):
            for j in range(i + 1, n):
                if num_list[i] > num_list[j]:
                    swaps += 1
        return swaps
